sql:
SELECT hcp_name, role
FROM healthcare_professionals
ORDER BY role ASC;

external_knowledge:
- DEATH_EVENT = 1 indicates a death event occurred during the treatment;
- access_type = 'edit' and access_type = 'view' distinguish between data modification and data access actions, respectively;
- specialization = 'Epidemiologist' identifies healthcare professionals specializing in epidemiology.

sql:
SELECT DISTINCT email
FROM healthcare_professionals
WHERE hcp_id IN (SELECT DISTINCT hcp_id FROM access_logs);

external_knowledge:
Cardiologist: A healthcare professional specialized in heart diseases; 
Outcome of treatment: Fatal (1) means the patient died, Non-fatal (0) means the patient survived; 
Follow-up status: Required (1) means follow-up with the patient is necessary, Not Required (0) means no follow-up is needed.
